import React from 'react';
import { Link } from 'react-router-dom';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from '../pages/PageStyle2.module.css';

function DashboardPage() {
  return (
    <EmployeeLayout title="Employee Dashboard">
      <div className={styles.statsGrid}>
        <Link to="/regempl" className={styles.statCard}><p>Register New Employee</p></Link>
        <Link to="/cust" className={styles.statCard}><p>Manage Customers</p></Link>
        <Link to="/empl" className={styles.statCard}><p>Manage Employees</p></Link>
      </div>
    </EmployeeLayout>
  );
}

export default DashboardPage;
